{
  "tags": [
    "Recurring Consents"
  ],
  "summary": "Busca informações de um consentimento.",
  "operationId": "automaticPaymentsGetRecurringConsentsConsentId",
  "description": "Método para buscar informações sobre um consentimento de longa duração.",
  "parameters": [
    {
      "name": "Authorization",
      "in": "header",
      "description": "Cabeçalho HTTP padrão. Permite que as credenciais sejam fornecidas dependendo do tipo de recurso solicitado",
      "required": true,
      "schema": {
        "type": "string",
        "pattern": "[\\w\\W\\s]*",
        "minLength": 1,
        "maxLength": 2048
      }
    },
    {
      "name": "x-customer-user-agent",
      "in": "header",
      "description": "Indica o user-agent que o usuário utiliza.",
      "required": false,
      "schema": {
        "type": "string",
        "pattern": "[\\w\\W\\s]*",
        "minLength": 1,
        "maxLength": 100
      }
    },
    {
      "name": "x-fapi-auth-date",
      "in": "header",
      "description": "Data em que o usuário logou pela última vez com o iniciador. Representada de acordo com a [RFC7231](https://tools.ietf.org/html/rfc7231).Exemplo: Sun, 10 Sep 2017 19:43:31 UTC",
      "required": false,
      "schema": {
        "type": "string",
        "pattern": "^(Mon|Tue|Wed|Thu|Fri|Sat|Sun), \\d{2} (Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec) \\d{4} \\d{2}:\\d{2}:\\d{2} (GMT|UTC)$",
        "minLength": 29,
        "maxLength": 29
      }
    },
    {
      "name": "x-fapi-customer-ip-address",
      "in": "header",
      "description": "O endereço IP do usuário se estiver atualmente logado com o iniciador.",
      "required": false,
      "schema": {
        "type": "string",
        "pattern": "[\\w\\W\\s]*",
        "minLength": 1,
        "maxLength": 100
      }
    },
    {
      "name": "x-fapi-interaction-id",
      "in": "header",
      "description": "Um UUID [RFC4122](https://tools.ietf.org/html/rfc4122) usado como um ID de correlação entre request e response. Campo de geração e envio obrigatório pela iniciadora (client) e o seu valor deve ser “espelhado” pela detentora (server) no cabeçalho de resposta. Caso não seja recebido ou se for recebido um valor inválido, a detentora deve gerar um x-fapi-interaction-id e retorná-lo na resposta com o HTTP status code 400. A iniciadora deve acatar o valor recebido da detentora..",
      "required": true,
      "schema": {
        "type": "string",
        "format": "uuid",
        "minLength": 1,
        "maxLength": 36,
        "pattern": "^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$",
        "example": "d78fc4e5-37ca-4da3-adf2-9b082bf92280"
      }
    },
    {
      "name": "recurringConsentId",
      "in": "path",
      "description": "O `recurringConsentId` é o identificador único do consentimento de longa duração e deverá ser um URN - Uniform Resource Name.  \nUm URN, conforme definido na [RFC8141](https://tools.ietf.org/html/rfc8141) é um Uniform Resource \nIdentifier - URI - que é atribuído sob o URI scheme \"urn\" e um namespace URN específico, com a intenção de que o URN \nseja um identificador de recurso persistente e independe da localização.  \nConsiderando a string urn:bancoex:C1DD33123 como exemplo para `recurringConsentId` temos:\n- o namespace(urn)\n- o identificador associado ao namespace da instituição detentora (bancoex).\n- o identificador específico dentro do namespace (C1DD33123).  \nInformações mais detalhadas sobre a construção de namespaces devem ser consultadas na [RFC8141](https://tools.ietf.org/html/rfc8141).\n",
      "required": true,
      "schema": {
        "type": "string",
        "pattern": "^urn:[a-zA-Z0-9][a-zA-Z0-9\\-]{0,31}:[a-zA-Z0-9()+,\\-.:=@;$_!*'%\\/?#]+$",
        "minLength": 1,
        "maxLength": 256
      }
    }
  ],
  "responses": {
    "200": {
      "description": "Objeto contendo as informações de consentimento para iniciação de pagamento automático.",
      "headers": {
        "x-fapi-interaction-id": {
          "description": "Um UUID [RFC4122](https://tools.ietf.org/html/rfc4122) usado como um ID de correlação entre request e response. Campo de geração e envio obrigatório pela iniciadora (client) e o seu valor deve ser “espelhado” pela detentora (server) no cabeçalho de resposta.\n",
          "schema": {
            "type": "string",
            "format": "uuid",
            "minLength": 1,
            "maxLength": 36,
            "pattern": "^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$",
            "example": "d78fc4e5-37ca-4da3-adf2-9b082bf92280"
          }
        },
        "x-v": {
          "description": "Cabeçalho que indica a versão implementada da API pela instituição financeira para atender à solicitação. Deve ser preenchido de forma completa, por exemplo: x-v : 1.0.2.\n",
          "required": true,
          "schema": {
            "type": "string",
            "pattern": "^\\d+\\.\\d+\\.\\d+$",
            "example": "1.0.0"
          }
        }
      },
      "content": {
        "application/jwt": {
          "schema": {
            "type": "object",
            "required": [
              "data",
              "links",
              "meta"
            ],
            "properties": {
              "data": {
                "type": "object",
                "description": "Objeto contendo as informações de consentimento para a iniciação de pagamento individual.",
                "required": [
                  "recurringConsentId",
                  "statusUpdateDateTime",
                  "loggedUser",
                  "status",
                  "creditors",
                  "creationDateTime",
                  "recurringConfiguration"
                ],
                "properties": {
                  "recurringConsentId": {
                    "type": "string",
                    "pattern": "^urn:[a-zA-Z0-9][a-zA-Z0-9\\-]{0,31}:[a-zA-Z0-9()+,\\-.:=@;$_!*'%\\/?#]+$",
                    "maxLength": 256,
                    "description": "Identificador único do consentimento de longa duração criado para a iniciação de pagamento solicitada. Deverá ser um URN - Uniform Resource Name. Um URN, conforme definido na [RFC8141](https://datatracker.ietf.org/doc/html/rfc8141) é um Uniform Resource Identifier - URI - que é atribuído sob o URI scheme \"urn\" e um namespace URN específico, com a intenção de que o URN seja um identificador de recurso persistente e independente da localização.\nConsiderando a string urn:bancoex:C1DD33123 como exemplo para `recurringConsentId` temos:  \n- o namespace(urn)  \n- o identificador associado ao namespace da instituição transmissora (bancoex)  \n- o identificador específico dentro do namespace (C1DD33123). Informações mais detalhadas sobre a construção de namespaces devem ser consultadas na [RFC8141](https://datatracker.ietf.org/doc/html/rfc8141).\n"
                  },
                  "statusUpdateDateTime": {
                    "type": "string",
                    "format": "date-time",
                    "example": "2021-05-21T08:30:00Z",
                    "pattern": "^(\\d{4})-(1[0-2]|0?[1-9])-(3[01]|[12][0-9]|0?[1-9])T(?:[01]\\d|2[0123]):(?:[012345]\\d):(?:[012345]\\d)Z$",
                    "maxLength": 20,
                    "description": "Data e hora em que o consentimento teve o status atualizado. Uma string com data e hora conforme especificação [RFC-3339](https://datatracker.ietf.org/doc/html/rfc3339), sempre com a utilização de timezone UTC(UTC time format).\n"
                  },
                  "loggedUser": {
                    "type": "object",
                    "description": "Usuário (pessoa natural) que encontra-se logado na instituição Iniciadora de Pagamento.",
                    "required": [
                      "document"
                    ],
                    "properties": {
                      "document": {
                        "type": "object",
                        "required": [
                          "identification",
                          "rel"
                        ],
                        "properties": {
                          "identification": {
                            "type": "string",
                            "maxLength": 11,
                            "description": "Número do documento de identificação oficial do usuário.",
                            "example": "11111111111",
                            "pattern": "^\\d{11}$"
                          },
                          "rel": {
                            "type": "string",
                            "maxLength": 3,
                            "description": "Tipo do documento de identificação oficial do usuário.",
                            "example": "CPF",
                            "pattern": "^[A-Z]{3}$"
                          }
                        }
                      }
                    }
                  },
                  "businessEntity": {
                    "type": "object",
                    "description": "Usuário (pessoa jurídica) que encontra-se logado na instituição Iniciadora de Pagamento.\n\n[Restrição] Preenchimento obrigatório se usuário logado na instituição Iniciadora de Pagamento for um CNPJ (pessoa jurídica).\n",
                    "required": [
                      "document"
                    ],
                    "properties": {
                      "document": {
                        "type": "object",
                        "required": [
                          "identification",
                          "rel"
                        ],
                        "properties": {
                          "identification": {
                            "type": "string",
                            "maxLength": 14,
                            "description": "Número do documento de identificação oficial do titular pessoa jurídica.",
                            "example": "11111111111111",
                            "pattern": "^[0-9A-Z]{12}[0-9]{2}$"
                          },
                          "rel": {
                            "type": "string",
                            "maxLength": 4,
                            "description": "Tipo do documento de identificação oficial do titular pessoa jurídica.",
                            "example": "CNPJ",
                            "pattern": "^[A-Z]{4}$"
                          }
                        }
                      }
                    }
                  },
                  "status": {
                    "type": "string",
                    "enum": [
                      "AWAITING_AUTHORISATION",
                      "PARTIALLY_ACCEPTED",
                      "AUTHORISED",
                      "REJECTED",
                      "REVOKED",
                      "CONSUMED"
                    ],
                    "example": "AWAITING_AUTHORISATION",
                    "description": "Status atual do consentimento recorrente de acordo com a máquina de estados\n- AWAITING_AUTHORISATION - Aguardando autorização\n- PARTIALLY_ACCEPTED - Parcialmente aceito\n- AUTHORISED - Autorizado\n- REJECTED - Rejeitado\n- REVOKED - Revogado\n- CONSUMED - Consumido\n"
                  },
                  "creditors": {
                    "type": "array",
                    "minItems": 1,
                    "items": {
                      "type": "object",
                      "description": "Objeto contendo os dados do recebedor (creditor).\n\n**Regras para Transferências inteligentes:**\n\n1. Para clientes pessoa física/natural: \n- Deve aceitar apenas um item no array; e; \n- O CPF informado deve ser o mesmo do `/data/loggedUser/document/identification`.\n\n2. Para clientes pessoa jurídica: \n- Não há limite para quantidade de itens no array; e; \n- O(s) CNPJ informado deve possuir a mesma raiz do CNPJ enviado no campo `/data/businessEntity/document/identification`.\n\n**Regras para Pix Automático:**\n\n- Apenas um item é permitido no array; e; \n- O documento informado deve ser de um recebedor pessoa jurídica.\n",
                      "required": [
                        "personType",
                        "cpfCnpj",
                        "name"
                      ],
                      "properties": {
                        "personType": {
                          "type": "string",
                          "enum": [
                            "PESSOA_NATURAL",
                            "PESSOA_JURIDICA"
                          ],
                          "example": "PESSOA_NATURAL",
                          "description": "Titular, pessoa natural ou juridica a quem se referem os dados de recebedor (creditor).\n"
                        },
                        "cpfCnpj": {
                          "type": "string",
                          "minLength": 11,
                          "maxLength": 14,
                          "pattern": "^([0-9]{11})$|^([0-9A-Z]{12}[0-9]{2})$",
                          "example": "58764789000137",
                          "description": "Identificação da pessoa envolvida na transação.  \nPreencher com o CPF ou CNPJ, de acordo com o valor escolhido no campo type.  \nO CPF será utilizado com 11 números e deverá ser informado sem pontos ou traços.  \nO CNPJ será utilizado com 14 números e deverá ser informado sem pontos ou traços.\n"
                        },
                        "name": {
                          "type": "string",
                          "pattern": "^([A-Za-zÀ-ÖØ-öø-ÿ,.@:&*+_<>()!?/\\\\$%\\d' -]+)$",
                          "maxLength": 120,
                          "example": "Marco Antonio de Brito",
                          "description": "Em caso de pessoa natural deve ser informado o nome completo do titular da conta do recebedor.  \nEm caso de pessoa jurídica deve ser informada a razão social ou o nome fantasia da conta do recebedor.\n"
                        }
                      }
                    }
                  },
                  "creationDateTime": {
                    "description": "Data e hora em que o consentimento foi criado. Uma string com data e hora conforme especificação [RFC-3339](https://datatracker.ietf.org/doc/html/rfc3339), sempre com a utilização de timezone UTC(UTC time format).",
                    "type": "string",
                    "format": "date-time",
                    "example": "2021-05-21T08:30:00Z",
                    "pattern": "^(\\d{4})-(1[0-2]|0?[1-9])-(3[01]|[12][0-9]|0?[1-9])T(?:[01]\\d|2[0123]):(?:[012345]\\d):(?:[012345]\\d)Z$",
                    "maxLength": 20
                  },
                  "expirationDateTime": {
                    "description": "Data e hora em que o consentimento deve deixar de ser válido. Uma string com data e hora conforme especificação [RFC-3339](https://datatracker.ietf.org/doc/html/rfc3339), sempre com a utilização de timezone UTC (UTC time format).\n\n[Restrição] Caso o consentimento seja para Pix Automático (\"automatic\" selecionado no oneOf \"/data/recurringConfiguration/\") o horário de expiração do consentimento precisa ser às 23:59:59 (UTC).\n",
                    "type": "string",
                    "format": "date-time",
                    "example": "2021-05-21T08:30:00Z",
                    "pattern": "^(\\d{4})-(1[0-2]|0?[1-9])-(3[01]|[12][0-9]|0?[1-9])T(?:[01]\\d|2[0123]):(?:[012345]\\d):(?:[012345]\\d)Z$",
                    "maxLength": 20
                  },
                  "additionalInformation": {
                    "description": "Deve ser preenchido sempre que o usuário pagador inserir alguma informação adicional no consentimento",
                    "type": "string",
                    "example": "Minha recorrência",
                    "pattern": "[\\w\\W\\s]*",
                    "maxLength": 140
                  },
                  "debtorAccount": {
                    "type": "object",
                    "description": "Objeto que contém a identificação da conta de origem do pagador. \n- Caso a ITP tenha coletado as informações de conta do usuário pagador, essas poderão ser enviadas no consentimento para a detentora neste objeto, ou; \n- Se não coletado pelo ITP, o usuário pagador precisará definir durante a autorização do consentimento. \n- Mesmo se enviado pela ITP, o usuário pagador pode alterar durante a autorização do consentimento.\n\n[Restrições]\n- Objeto obrigatório que deverá ser retornado quando o consentimento estiver ou passar pelo status AUTHORISED;\n",
                    "required": [
                      "ispb",
                      "number",
                      "accountType"
                    ],
                    "properties": {
                      "ispb": {
                        "type": "string",
                        "minLength": 8,
                        "maxLength": 8,
                        "pattern": "^[0-9A-Z]{8}$",
                        "example": "12345678",
                        "description": "Deve ser preenchido com o ISPB (Identificador do Sistema de Pagamentos Brasileiros) do participante do SPI (Sistema de pagamentos instantâneos) somente com números.\n"
                      },
                      "issuer": {
                        "type": "string",
                        "minLength": 1,
                        "maxLength": 4,
                        "pattern": "^[0-9]{1,4}$",
                        "example": "1774",
                        "description": "Código da Agência emissora da conta sem dígito. \n(Agência é a dependência destinada ao atendimento aos clientes, ao público em geral e aos associados de cooperativas de crédito, \nno exercício de atividades da instituição, não podendo ser móvel ou transitória).\n\n[Restrição] Preenchimento obrigatório para os seguintes tipos de conta: CACC (CONTA_DEPOSITO_A_VISTA) e SVGS (CONTA_POUPANCA).\n"
                      },
                      "number": {
                        "type": "string",
                        "minLength": 1,
                        "maxLength": 20,
                        "pattern": "^[0-9]{1,20}$",
                        "example": "1234567890",
                        "description": "Deve ser preenchido com o número da conta transacional do usuário pagador, com dígito verificador (se este existir), se houver valor alfanumérico, este deve ser convertido para 0.\n"
                      },
                      "accountType": {
                        "type": "string",
                        "enum": [
                          "CACC",
                          "SVGS",
                          "TRAN"
                        ],
                        "example": "CACC",
                        "description": "Tipos de contas usadas para pagamento. \nModalidades tradicionais previstas pela Resolução 4.753, não contemplando contas vinculadas, \nconta de domiciliados no exterior, contas em moedas estrangeiras e conta correspondente moeda eletrônica.  \nSegue descrição de cada valor do ENUM.\n\n- CACC - Current - Conta Corrente.\n- SVGS - Savings - Conta de Poupança.\n- TRAN - TransactingAccount - Conta de Pagamento pré-paga.\n"
                      },
                      "ibgeTownCode": {
                        "type": "string",
                        "minLength": 7,
                        "maxLength": 7,
                        "pattern": "^\\d{7}$",
                        "example": "5300108",
                        "description": "Campo utilizado pela iniciadora para cálculo do dia útil de liquidação do pagamento (vide especificação do endToEndId) baseado no município de cadastro do usuário pagador no detentor.\n\n[Restrições]\nCampo de preenchimento obrigatório quando o oneOf utilizado do recurringConfiguration for “automatic”, e o consentimento passar pelo estado AUTHORISED.\n"
                      }
                    }
                  },
                  "rejection": {
                    "type": "object",
                    "description": "Objeto contendo as informações de rejeição dos consentimentos.\n\n[Restrição] Campo de preenchimento obrigatório caso status do consentimento igual a \"REJECTED\".\n",
                    "required": [
                      "rejectedBy",
                      "rejectedFrom",
                      "rejectedAt"
                    ],
                    "properties": {
                      "rejectedBy": {
                        "type": "string",
                        "enum": [
                          "INICIADORA",
                          "USUARIO",
                          "DETENTORA"
                        ],
                        "example": "INICIADORA",
                        "description": "Quem iniciou a solicitação de rejeição\n- INICIADORA\n- USUARIO\n- DETENTORA\n"
                      },
                      "rejectedFrom": {
                        "type": "string",
                        "enum": [
                          "INICIADORA",
                          "DETENTORA"
                        ],
                        "example": "DETENTORA",
                        "description": "Canal onde iniciou-se o processo de rejeição \n- INICIADORA\n- DETENTORA\n"
                      },
                      "rejectedAt": {
                        "type": "string",
                        "format": "date-time",
                        "example": "2021-05-21T08:30:00Z",
                        "pattern": "^(\\d{4})-(1[0-2]|0?[1-9])-(3[01]|[12][0-9]|0?[1-9])T(?:[01]\\d|2[0123]):(?:[012345]\\d):(?:[012345]\\d)Z$",
                        "maxLength": 20,
                        "description": "Data e hora em que o consentimento foi rejeitado"
                      },
                      "reason": {
                        "type": "object",
                        "description": "Informações sobre o motivo da rejeição \n",
                        "required": [
                          "code",
                          "detail"
                        ],
                        "properties": {
                          "code": {
                            "type": "string",
                            "enum": [
                              "NAO_INFORMADO",
                              "FALHA_INFRAESTRUTURA",
                              "TEMPO_EXPIRADO_AUTORIZACAO",
                              "REJEITADO_USUARIO",
                              "CONTAS_ORIGEM_DESTINO_IGUAIS",
                              "CONTA_NAO_PERMITE_PAGAMENTO",
                              "AUTENTICACAO_DIVERGENTE",
                              "FLUXO_NAO_SUPORTADO_PRODUTO"
                            ],
                            "example": "AUTENTICACAO_DIVERGENTE",
                            "description": "Código indicador do motivo de rejeição.\n- NAO_INFORMADO\n- FALHA_INFRAESTRUTURA\n- TEMPO_EXPIRADO_AUTORIZACAO\n- REJEITADO_USUARIO\n- CONTAS_ORIGEM_DESTINO_IGUAIS\n- CONTA_NAO_PERMITE_PAGAMENTO\n- AUTENTICACAO_DIVERGENTE\n- FLUXO_NAO_SUPORTADO_PRODUTO\n"
                          },
                          "detail": {
                            "type": "string",
                            "pattern": "[\\w\\W\\s]*",
                            "maxLength": 2048,
                            "description": "Detalhe sobre o motivo de rejeição indicado no campo `/data/rejection/reason/code`\n- NAO_INFORMADO: Não informada pela detentora de conta;\n- FALHA_INFRAESTRUTURA: [Descrição de qual falha na infraestrutura inviabilizou o processamento];\n- TEMPO_EXPIRADO_AUTORIZACAO: Consentimento expirou antes que o usuário pudesse confirmá-lo;\n- REJEITADO_USUARIO: O usuário rejeitou a autorização do consentimento;\n- CONTAS_ORIGEM_DESTINO_IGUAIS: A conta selecionada é igual à conta destino e não permite realizar esse pagamento;\n- CONTA_NAO_PERMITE_PAGAMENTO: A conta selecionada é do tipo [salario/investimento/liquidação/outros] e não permite realizar esse pagamento;\n- AUTENTICACAO_DIVERGENTE : Usuário autenticado no detentor diverge do usuário autenticado no iniciador;\n- FLUXO_NAO_SUPORTADO_PRODUTO: O consentimento está configurado para um produto ainda não suportado pelo fluxo que iniciou a solicitação.\n",
                            "example": "O usuário rejeitou a autorização do consentimento"
                          }
                        }
                      }
                    }
                  },
                  "revocation": {
                    "type": "object",
                    "description": "Objeto contendo as informações de revogação dos consentimentos.\n\n[Restrição] Campo de preenchimento obrigatório caso status do consentimento igual a \"REVOKED\".\n",
                    "required": [
                      "revokedBy",
                      "revokedFrom",
                      "revokedAt"
                    ],
                    "properties": {
                      "revokedBy": {
                        "type": "string",
                        "enum": [
                          "INICIADORA",
                          "USUARIO",
                          "DETENTORA"
                        ],
                        "example": "INICIADORA",
                        "description": "Quem iniciou a solicitação de revogação  \n- INICIADORA\n- USUARIO\n- DETENTORA\n"
                      },
                      "revokedFrom": {
                        "type": "string",
                        "enum": [
                          "INICIADORA",
                          "DETENTORA"
                        ],
                        "example": "DETENTORA",
                        "description": "Canal onde iniciou-se o processo de revogação   \n- INICIADORA  \n- DETENTORA  \n"
                      },
                      "revokedAt": {
                        "type": "string",
                        "format": "date-time",
                        "example": "2021-05-21T08:30:00Z",
                        "pattern": "^(\\d{4})-(1[0-2]|0?[1-9])-(3[01]|[12][0-9]|0?[1-9])T(?:[01]\\d|2[0123]):(?:[012345]\\d):(?:[012345]\\d)Z$",
                        "maxLength": 20,
                        "description": "Data e hora em que o consentimento foi revogado"
                      },
                      "reason": {
                        "type": "object",
                        "description": "Informações sobre o motivo da revogação\n",
                        "required": [
                          "code",
                          "detail"
                        ],
                        "properties": {
                          "code": {
                            "type": "string",
                            "enum": [
                              "NAO_INFORMADO",
                              "REVOGADO_USUARIO",
                              "REVOGADO_RECEBEDOR"
                            ],
                            "example": "REVOGADO_RECEBEDOR",
                            "description": "Código indicador do motivo da revogação\n"
                          },
